import math
from collections import Counter

class Solution:
    def numberOfSubsequences(self, nums):
        n = len(nums)

        def key(x, y):
            g = math.gcd(x, y)
            return (x // g, y // g)

        left_freq = [None] * n
        for q in range(n):
            c = Counter()
            for p in range(0, q - 1):
                c[key(nums[p], nums[q])] += 1
            left_freq[q] = c

        right_freq = [None] * n
        for r in range(n):
            c = Counter()
            for s in range(r + 2, n):
                c[key(nums[s], nums[r])] += 1
            right_freq[r] = c

        total = 0
        acc = Counter()
        for q in range(n - 1, -1, -1):
            r2 = q + 2
            if r2 <= n - 1:
                for kk, vv in right_freq[r2].items():
                    acc[kk] += vv
            if left_freq[q]:
                for kk, vv in left_freq[q].items():
                    total += vv * acc.get(kk, 0)
        return total

