var numberOfSubsequences = function(nums) {
    const n = nums.length;
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
    function key(x, y) { const g = gcd(x, y); return (x / g) + "," + (y / g); }

    const leftFreq = new Array(n);
    for (let q = 0; q < n; q++) {
        const m = new Map();
        for (let p = 0; p < q - 1; p++) {
            const k = key(nums[p], nums[q]);
            m.set(k, (m.get(k) || 0) + 1);
        }
        leftFreq[q] = m;
    }
    const rightFreq = new Array(n);
    for (let r = 0; r < n; r++) {
        const m = new Map();
        for (let s = r + 2; s < n; s++) {
            const k = key(nums[s], nums[r]);
            m.set(k, (m.get(k) || 0) + 1);
        }
        rightFreq[r] = m;
    }
    let total = 0;
    const acc = new Map();
    for (let q = n - 1; q >= 0; q--) {
        const r2 = q + 2;
        if (r2 <= n - 1) {
            for (const [kk, vv] of rightFreq[r2]) {
                acc.set(kk, (acc.get(kk) || 0) + vv);
            }
        }
        for (const [kk, vv] of leftFreq[q]) {
            total += vv * (acc.get(kk) || 0);
        }
    }
    return total;
};
